import shutil
import os

def eden_fonksiyon(archive_path: str, extract_dir: str):
    try:
        os.makedirs(extract_dir, exist_ok=True)
        shutil.unpack_archive(archive_path, extract_dir)
    except FileNotFoundError:
        print(f"Hata: Arşiv dosyası bulunamadı: {archive_path}")
    except shutil.ReadError:
        print(f"Hata: '{archive_path}' dosyası geçerli bir arşiv formatında değil veya bozuk.")
    except Exception as e:
        print(f"Beklenmeyen bir hata oluştu: {e}")
